mapper.update:
UPDATE slip_detail
SET returned = #{returned},
    returned_date = #{returnedDate},
    planned_label = #{plannedLabel}
WHERE id = #{id}

mapper.select:
SELECT s.id AS slipId, s.slip_no AS slipNo, s.staff_name AS staffName, s.customer_name AS customerName, s.loan_date AS loanDate, s.return_date AS returnDate, d.id, d.code, d.name, d.price, d.tax_price AS taxPrice, d.credit, d.planned_label AS plannedLabel, d.media_name AS mediaName, d.release_date AS releaseDate, d.note, d.returned FROM slip s JOIN slip_detail d ON s.id = d.slip_id WHERE s.slip_no LIKE CONCAT(#{slipNo}, '%')
AND s.loan_date >= #{loanDateFrom}
AND s.loan_date <= #{loanDateTo}
ORDER BY d.id

SELECT s.id AS slipId, s.slip_no AS slipNo, s.staff_name AS staffName, s.customer_name AS customerName, s.loan_date AS loanDate, s.return_date AS returnDate, d.id, d.code, d.name, d.price, d.tax_price AS taxPrice, d.credit, d.planned_label AS plannedLabel, d.media_name AS mediaName, d.release_date AS releaseDate, d.note, d.returned FROM slip s JOIN slip_detail d ON s.id = d.slip_id WHERE d.code LIKE CONCAT(#{code}, '%')
AND s.loan_date >= #{loanDateFrom}
AND s.loan_date <= #{loanDateTo}
ORDER BY s.slip_no, d.id
